s3 = boto3.client('s3')
sns = boto3.client('sns')

def lambda_handler(event, context):
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']

    # Read image from S3
    response = s3.get_object(Bucket=bucket_name, Key=object_key)
    image_data = response['Body'].read()

    # Process the image (example: convert to grayscale)
    processed_image_data = process_image(image_data)

    # Write result back to S3
    output_bucket_name = 'processed-images-bucket'
    output_object_key = f'processed_{object_key}'
    s3.put_object(Bucket=output_bucket_name, Key=output_object_key, Body=processed_image_data)

    # Send notification via SNS
    sns.publish(
        TopicArn='arn:aws:sns:us-east-1:123456789012:MyTopic',
        Message=json.dumps({'default': f'Image {object_key} processed successfully'}),
        Subject='Image Processing Notification'
    )

    # Log to CloudWatch
    print(f'Processed image {object_key}')

